pub inline fn nfdQuickCheck(cp: CodePoint) QuickCheck {
    if (cp > 0x10FFFF) return .unknown;
    const page = nfd_qc_level1[cp >> 8];
    return nfd_qc_level2[page][cp & 0xFF];
}

