pub inline fn nfkcCaseFoldMap(cp: CodePoint) ?[]const CodePoint {
    if (cp > 0x10FFFF) return null;
    const page = nfkc_cf_level1[cp >> 8];
    const idx = nfkc_cf_level2[page][cp & 0xFF];
    if (idx == 0) return null;
    return nfkc_cf_mappings[idx];
}

