    &.{ 0x9829 },     &.{ 0x295B6 },     &.{ 0x98E2 },     &.{ 0x4B33 },
    &.{ 0x9929 },     &.{ 0x99A7 },     &.{ 0x99C2 },     &.{ 0x99FE },
    &.{ 0x4BCE },     &.{ 0x29B30 },     &.{ 0x9C40 },     &.{ 0x9CFD },
    &.{ 0x4CCE },     &.{ 0x4CED },     &.{ 0x9D67 },     &.{ 0x2A0CE },
    &.{ 0x4CF8 },     &.{ 0x2A105 },     &.{ 0x2A20E },     &.{ 0x2A291 },
    &.{ 0x9EBB },     &.{ 0x4D56 },     &.{ 0x9EF9 },     &.{ 0x9EFE },
    &.{ 0x9F05 },     &.{ 0x9F0F },     &.{ 0x9F16 },     &.{ 0x9F3B },
    &.{ 0x2A600 }, 
